{"command": "cd /testbed && python -c "
import sqlfluff
import yaml
import os

# Load test cases
with open('test/fixtures/rules/std_rule_cases/L060.yml', 'r') as f:
    test_data = yaml.safe_load(f)

print('Running L060 test cases...')
for test_name, test_case in test_data.items():
    if test_name == 'rule':
        continue

    print(f'\\nTest: {test_name}')

    if 'fail_str' in test_case:
        print('  Testing fail case:')
        result = sqlfluff.lint(test_case['fail_str'])
        l060_results = [r for r in result if r['code'] == 'L060']
        if l060_results:
            print(f'    Found {len(l060_results)} L060 violation(s)')
            for r in l060_results:
                print(f'    - {r[\"description\"]}')
        else:
            print('    No L060 violations found (unexpected)')

    if 'pass_str' in test_case:
        print('  Testing pass case:')
        result = sqlfluff.lint(test_case['pass_str'])
        l060_results = [r for r in result if r['code'] == 'L060']
        if l060_results:
            print(f'    Found {len(l060_results)} L060 violation(s) (unexpected)')
            for r in l060_results:
                print(f'    - {r[\"description\"]}')
        else:
            print('    No L060 violations (expected)')
""}

